import React, { useState, useEffect } from 'react';
import { CamSvg, API_URL, VK_BOT } from '../App';
import bridge from '@vkontakte/vk-bridge';

const TYPES = [
  { v:'',          l:'Какой тип съёмки вас интересует?' },
  { v:'portrait',  l:'Портретная'      },
  { v:'family',    l:'Семейная'        },
  { v:'lovestory', l:'Love Story'      },
  { v:'pregnancy', l:'Беременность'    },
  { v:'kids',      l:'Детская'         },
  { v:'birthday',  l:'День рождения'   },
  { v:'business',  l:'Бизнес / Деловая'},
];

export default function Booking({ user, onBot }) {
  const [f, setF] = useState({ name:'', phone:'', date:'', time:'', type:'', wish:'' });
  const [err, setErr] = useState({});
  const [busy, setBusy] = useState(false);
  const [ok, setOk] = useState(false);

  useEffect(() => {
    if (user && !f.name)
      setF(p => ({ ...p, name:`${user.first_name} ${user.last_name}` }));
  }, [user]);

  const upd = k => e => { setF(p=>({...p,[k]:e.target.value})); setErr(p=>({...p,[k]:''})); };

  const phoneInput = e => {
    let v = e.target.value.replace(/\D/g,'');
    if (v.startsWith('8')) v = '7'+v.slice(1);
    if (v.startsWith('7')) {
      v = v.slice(0,11);
      let s='+7';
      if(v.length>1) s+=' ('+v.slice(1,4);
      if(v.length>=4) s+=') '+v.slice(4,7);
      if(v.length>=7) s+='-'+v.slice(7,9);
      if(v.length>=9) s+='-'+v.slice(9,11);
      e.target.value=s;
    }
    setF(p=>({...p,phone:e.target.value}));
    setErr(p=>({...p,phone:''}));
  };

  const validate = () => {
    const e={};
    if(!f.name.trim()) e.name='Введите имя';
    if(!f.phone||f.phone.replace(/\D/g,'').length<11) e.phone='Введите корректный номер';
    if(!f.date) e.date='Выберите дату';
    if(!f.type) e.type='Выберите тип съёмки';
    setErr(e);
    return !Object.keys(e).length;
  };

  const submit = async e => {
    e.preventDefault();
    if(!validate()) return;
    setBusy(true);
    const tl = TYPES.find(t=>t.v===f.type)?.l || f.type;
    const ds = f.date
      ? new Date(f.date).toLocaleDateString('ru-RU',{day:'numeric',month:'long',year:'numeric'})
      : '—';
    const msg = [
      '📸 Новая заявка — Твой Контентный Сочи',
      '',
      `👤 ${f.name}`,
      `📞 ${f.phone}`,
      `📅 ${ds}${f.time?' в '+f.time:''}`,
      `🎯 ${tl}`,
      f.wish?`💬 ${f.wish}`:'',
      '📱 VK Mini App',
    ].filter(Boolean).join('\n');

    try { await fetch(API_URL,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:msg})}); }
    catch(e){ console.log('demo:', msg); }

    setBusy(false);
    setOk(true);
  };

  if (ok) return (
    <div className="page page--center">
      <div className="success-cam"><CamSvg size={52}/></div>
      <h2 className="success-title">Заявка отправлена</h2>
      <p className="success-text">Отвечу в течение часа!</p>
      <button className="btn-gold" style={{marginTop:28}} onClick={onBot}>Написать в ВКонтакте</button>
      <button className="btn-ghost" style={{marginTop:12}}
        onClick={()=>{ setOk(false); setF({name:'',phone:'',date:'',time:'',type:'',wish:''}); }}>
        Новая заявка
      </button>
    </div>
  );

  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="page">
      <div className="page-head">
        <span className="lbl">Запись</span>
        <h2 className="page-title">Начнём вашу <em>историю</em></h2>
        <div className="gold-line"/>
      </div>

      <form onSubmit={submit} noValidate className="form">
        <Field label="Ваше имя" error={err.name}>
          <input className="inp" placeholder="Как вас зовут?" value={f.name} onChange={upd('name')} autoComplete="name"/>
        </Field>

        <Field label="Номер телефона" error={err.phone}>
          <input className="inp" type="tel" placeholder="+7 (___) ___-__-__" onChange={phoneInput} autoComplete="tel"/>
        </Field>

        <div className="form-row2">
          <Field label="Дата" error={err.date}>
            <input className="inp" type="date" min={today} value={f.date} onChange={upd('date')}/>
          </Field>
          <Field label="Время">
            <input className="inp" type="time" value={f.time} onChange={upd('time')}/>
          </Field>
        </div>

        <Field label="Тип съёмки" error={err.type}>
          <select className="inp sel" value={f.type} onChange={upd('type')}>
            {TYPES.map(t=>(
              <option key={t.v} value={t.v} disabled={!t.v}>{t.l}</option>
            ))}
          </select>
        </Field>

        <Field label="Пожелания (необязательно)">
          <input className="inp" placeholder="Локация, особые пожелания..." value={f.wish} onChange={upd('wish')}/>
        </Field>

        <div className="form-foot">
          <button type="submit" className="btn-gold btn-full" disabled={busy}>
            {busy?'Отправляем...':'Отправить заявку'}
          </button>
          <p className="form-note">Заявка придёт мне в ВКонтакте — отвечу в течение часа</p>
        </div>
      </form>
    </div>
  );
}

function Field({ label, error, children }) {
  return (
    <div className={`field${error?' field--err':''}`}>
      <label className="field-lbl">{label}</label>
      {children}
      {error && <span className="field-err">{error}</span>}
    </div>
  );
}
