import React, { useState, useEffect } from 'react';
import bridge from '@vkontakte/vk-bridge';
import Gallery  from './panels/Gallery';
import Booking  from './panels/Booking';
import Services from './panels/Services';

// ─── НАСТРОЙКИ (замените на ваши) ────────────────────────────────
export const VK_BOT   = 'https://vk.me/sochi_art_bot';
export const API_URL  = 'https://YOUR_SERVER.onrender.com/vk-notify';
export const BRAND    = 'Твой Контентный Сочи';
// ─────────────────────────────────────────────────────────────────

const tabs = [
  { id:'gallery',  icon:<IconPhoto/>,    label:'Работы'    },
  { id:'booking',  icon:<IconCal/>,      label:'Записаться'},
  { id:'services', icon:<IconPrice/>,    label:'Услуги'    },
];

export default function App() {
  const [tab,  setTab]  = useState('gallery');
  const [user, setUser] = useState(null);

  useEffect(() => {
    bridge.send('VKWebAppInit');
    bridge.send('VKWebAppGetUserInfo').then(setUser).catch(()=>{});
  }, []);

  const openBot = () =>
    bridge.send('VKWebAppOpenLink', { link: VK_BOT }).catch(()=> window.open(VK_BOT,'_blank'));

  return (
    <div className="app">
      <header className="app-header">
        <div className="app-logo">
          <CamSvg size={20}/>
          <span>{BRAND}</span>
        </div>
        <button className="header-msg-btn" onClick={openBot} aria-label="Написать">
          <MsgIcon/>
        </button>
      </header>

      <main className="app-body">
        {tab==='gallery'  && <Gallery  user={user} onBook={()=>setTab('booking')} onBot={openBot}/>}
        {tab==='booking'  && <Booking  user={user} onBot={openBot}/>}
        {tab==='services' && <Services onBook={()=>setTab('booking')} onBot={openBot}/>}
      </main>

      <nav className="app-tabs">
        {tabs.map(t => (
          <button
            key={t.id}
            className={`tab-btn${tab===t.id?' tab-btn--active':''}`}
            onClick={()=>setTab(t.id)}
          >
            {t.icon}
            <span>{t.label}</span>
          </button>
        ))}
      </nav>
    </div>
  );
}

