import React, { useState } from 'react';
import { CamSvg } from '../App';

const CATS = [
  { id:'all',       label:'Все работы'   },
  { id:'portrait',  label:'Портрет'      },
  { id:'family',    label:'Семейная'     },
  { id:'lovestory', label:'Love Story'   },
  { id:'pregnancy', label:'Беременность' },
  { id:'kids',      label:'Детская'      },
  { id:'birthday',  label:'День рождения'},
  { id:'business',  label:'Бизнес'       },
];

// ── ФОТО ── вставьте прямые ссылки из Telegram-канала ─────────────
// Как получить ссылку: t.me/s/sochisfotograph → правая кнопка на фото
// → "Скопировать адрес изображения" → вставьте в url
const PHOTOS = [
  { id:1,  cat:'lovestory', label:'Love Story · Набережная',     url:'' },
  { id:2,  cat:'portrait',  label:'Портрет · Море',               url:'' },
  { id:3,  cat:'family',    label:'Семейная · Роза Хутор',        url:'' },
  { id:4,  cat:'pregnancy', label:'Беременность · Сочи',          url:'' },
  { id:5,  cat:'kids',      label:'Детская · Пляж',               url:'' },
  { id:6,  cat:'lovestory', label:'Love Story · Горы',            url:'' },
  { id:7,  cat:'portrait',  label:'Портрет · Закат',              url:'' },
  { id:8,  cat:'business',  label:'Бизнес · Деловой образ',       url:'' },
  { id:9,  cat:'family',    label:'Семейная · Лето',              url:'' },
  { id:10, cat:'birthday',  label:'День рождения',                url:'' },
  { id:11, cat:'portrait',  label:'Портрет · Горы',               url:'' },
  { id:12, cat:'lovestory', label:'Love Story · Вечер',           url:'' },
];

export default function Gallery({ user, onBook, onBot }) {
  const [cat,   setCat]   = useState('all');
  const [light, setLight] = useState(null);

  const photos = cat === 'all' ? PHOTOS : PHOTOS.filter(p => p.cat === cat);

  return (
    <div className="page">

      {/* ── Hero ── */}
      <div className="hero">
        <div className="hero-cam"><CamSvg size={48}/></div>
        <div className="hero-line"/>
        <p className="hero-sub">Фотограф · Сочи</p>
        <h1 className="hero-title">Избранные <em>работы</em></h1>
        {user && <p className="hero-greeting">Добро пожаловать, {user.first_name}</p>}
        <div className="hero-actions">
          <button className="btn-gold" onClick={onBook}>Записаться на съёмку</button>
          <button className="btn-ghost" onClick={onBot}>Написать фотографу</button>
        </div>
      </div>

      {/* ── Категории ── */}
      <div className="cats-wrap">
        <div className="cats">
          {CATS.map(c => (
            <button
              key={c.id}
              className={`cat${cat===c.id?' cat--on':''}`}
              onClick={() => setCat(c.id)}
            >
              {c.label}
            </button>
          ))}
        </div>
      </div>

      {/* ── Сетка ── */}
      <div className="grid">
        {photos.map((p, i) => (
          <div
            key={p.id}
            className={`grid-item${i===0&&cat==='all'?' grid-item--tall':''}`}
            onClick={() => setLight(p)}
          >
            {p.url
              ? <img src={p.url} alt={p.label} loading="lazy"/>
              : <Placeholder/>
            }
            <div className="grid-label">{p.label}</div>
          </div>
        ))}
      </div>

      <p className="grid-count">
        {photos.length} {photos.length===1?'работа':'работ'}
        {cat!=='all'&&` · ${CATS.find(c=>c.id===cat)?.label}`}
      </p>

      {/* ── Lightbox ── */}
      {light && (
        <div className="lb" onClick={() => setLight(null)}>
          <div className="lb-box" onClick={e => e.stopPropagation()}>
            <button className="lb-close" onClick={() => setLight(null)}>✕</button>
            {light.url
              ? <img className="lb-img" src={light.url} alt={light.label}/>
              : <div className="lb-empty"><Placeholder big/></div>
            }
            <p className="lb-label">{light.label}</p>
            <button className="btn-gold" style={{marginTop:16}}
              onClick={() => { setLight(null); onBook(); }}>
              Записаться на такую съёмку
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function Placeholder({ big }) {
  return (
    <div className={`ph${big?' ph--big':''}`}>
      <CamSvg size={big?48:28}/>
      {big && <span className="ph-hint">Добавьте фото из Telegram</span>}
    </div>
  );
}
